import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [search, setSearch] = useState("");
  const [slots, setSlots] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/auth/workers")
      .then(res => setWorkers(res.data));
  }, []);

  const bookWorker = async (worker) => {

    await axios.post("http://localhost:5000/api/jobs/create", {
      workerName: worker.name,
      labourId: worker._id,
      workType: worker.skills?.join(", "),
      price: worker.price,
      timeSlots: slots
    });

    alert("Booking Request Sent");
  };

  return (
    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1>Find Workers</h1>

        <input
          placeholder="Search worker skill..."
          style={styles.search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <div style={styles.slotBox}>
          <input placeholder="Time Slot 1" onChange={e => setSlots([e.target.value])}/>
          <input placeholder="Time Slot 2" onChange={e => setSlots([...slots, e.target.value])}/>
          <input placeholder="Time Slot 3" onChange={e => setSlots([...slots, e.target.value])}/>
          <input placeholder="Time Slot 4" onChange={e => setSlots([...slots, e.target.value])}/>
        </div>

        <div style={styles.grid}>

          {workers
            .filter(w =>
              w.skills?.join(" ").toLowerCase().includes(search.toLowerCase())
            )
            .map(worker => (

            <div key={worker._id} style={styles.card}>

              <h2>{worker.name}</h2>

              <p><strong>Skills:</strong> {worker.skills?.join(", ")}</p>

              <p><strong>Charge:</strong> ₹{worker.price}</p>

              <button
                style={styles.bookBtn}
                onClick={() => bookWorker(worker)}
              >
                Book Worker
              </button>

            </div>
          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {
  page: {
    background: "#f4f7fb",
    minHeight: "100vh",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px"
  },

  search: {
    width: "350px",
    padding: "12px",
    borderRadius: "10px",
    border: "1px solid #ddd",
    marginBottom: "20px"
  },

  slotBox: {
    display: "grid",
    gridTemplateColumns: "repeat(2,1fr)",
    gap: "10px",
    marginBottom: "30px"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "25px",
    borderRadius: "16px",
    boxShadow: "0 5px 15px rgba(0,0,0,0.08)"
  },

  bookBtn: {
    marginTop: "15px",
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "12px 20px",
    borderRadius: "10px",
    cursor: "pointer"
  }
};
